import { useEffect, useState } from 'react'
import * as api from '../api/client'
import type { TodoListItem } from '../api/types'
import TodoItemRow from './TodoItemRow'
import AddTodoForm from './AddTodoForm'

interface Props {
  listId: number
}

function TodoListView({ listId }: Props) {
  const [items, setItems] = useState<TodoListItem[]>([])
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState<string | null>(null)

  useEffect(() => {
    let cancelled = false
    setLoading(true)
    api
      .getItems(listId)
      .then((data) => {
        if (!cancelled) setItems(data)
      })
      .catch((e: Error) => {
        if (!cancelled) setError(e.message)
      })
      .finally(() => {
        if (!cancelled) setLoading(false)
      })
    return () => {
      cancelled = true
    }
  }, [listId])

  async function handleAdd(description: string) {
    try {
      const created = await api.createItem(listId, description)
      setItems((prev) => [...prev, created])
    } catch (e) {
      setError((e as Error).message)
    }
  }

  async function handleToggle(item: TodoListItem) {
    try {
      const updated = await api.updateItem(listId, item.id, {
        description: item.description,
        isCompleted: !item.isCompleted,
      })
      setItems((prev) => prev.map((i) => (i.id === updated.id ? updated : i)))
    } catch (e) {
      setError((e as Error).message)
    }
  }

  async function handleDelete(item: TodoListItem) {
    try {
      await api.deleteItem(listId, item.id)
      setItems((prev) => prev.filter((i) => i.id !== item.id))
    } catch (e) {
      setError((e as Error).message)
    }
  }

  return (
    <section className="todo-list">
      <AddTodoForm onAdd={handleAdd} disabled={loading} />
      {error && <div className="banner banner-error">{error}</div>}
      {loading ? (
        <p className="muted">Loading…</p>
      ) : items.length === 0 ? (
        <p className="muted">No todos yet. Add your first one above.</p>
      ) : (
        <ul className="todo-rows">
          {items.map((item) => (
            <TodoItemRow
              key={item.id}
              item={item}
              onToggle={handleToggle}
              onDelete={handleDelete}
            />
          ))}
        </ul>
      )}
    </section>
  )
}

export default TodoListView

import type { TodoListItem } from '../api/types'

interface Props {
  item: TodoListItem
  onToggle: (item: TodoListItem) => void
  onDelete: (item: TodoListItem) => void
}

function TodoItemRow({ item, onToggle, onDelete }: Props) {
  return (
    <li className={`todo-row${item.isCompleted ? ' completed' : ''}`}>
      <label className="todo-row-label">
        <input
          type="checkbox"
          checked={item.isCompleted}
          onChange={() => onToggle(item)}
        />
        <span>{item.description}</span>
      </label>
      <button
        type="button"
        className="todo-row-delete"
        aria-label={`Delete ${item.description}`}
        onClick={() => onDelete(item)}
      >
        ×
      </button>
    </li>
  )
}

export default TodoItemRow

import { useState, type FormEvent } from 'react'

interface Props {
  onAdd: (description: string) => Promise<void> | void
  disabled?: boolean
}

function AddTodoForm({ onAdd, disabled }: Props) {
  const [value, setValue] = useState('')
  const [submitting, setSubmitting] = useState(false)

  async function handleSubmit(e: FormEvent) {
    e.preventDefault()
    const trimmed = value.trim()
    if (!trimmed || submitting) return
    setSubmitting(true)
    try {
      await onAdd(trimmed)
      setValue('')
    } finally {
      setSubmitting(false)
    }
  }

  return (
    <form className="add-todo-form" onSubmit={handleSubmit}>
      <input
        type="text"
        placeholder="Add a todo..."
        value={value}
        onChange={(e) => setValue(e.target.value)}
        disabled={disabled || submitting}
      />
      <button type="submit" disabled={disabled || submitting || !value.trim()}>
        Add
      </button>
    </form>
  )
}

export default AddTodoForm

