content.text:
### Implement Optimistic UI Updates for Form Submissions with React's useOptimistic Hook

Source: https://github.com/reactjs/react.dev/blob/main/src/content/reference/react-dom/components/form.md

This example demonstrates how to use the `useOptimistic` hook in React to immediately update the UI after a form submission, giving the impression of speed. It shows how to display a 'Sending...' status for messages before they are confirmed by a backend service, and then update the state once the asynchronous operation completes. The `App.js` component manages the optimistic state and renders messages, while `actions.js` simulates an asynchronous message delivery.

```javascript
import { useOptimistic, useState, useRef } from "react";
import { deliverMessage } from "./actions.js";

function Thread({ messages, sendMessage }) {
  const formRef = useRef();
  async function formAction(formData) {
    addOptimisticMessage(formData.get("message"));
    formRef.current.reset();
    await sendMessage(formData);
  }
  const [optimisticMessages, addOptimisticMessage] = useOptimistic(
    messages,
    (state, newMessage) => [
      ...state,
      {
        text: newMessage,
        sending: true
      }
    ]
  );

  return (
    <>
      {optimisticMessages.map((message, index) => (
        <div key={index}>
          {message.text}
          {!!message.sending && <small> (Sending...)</small>}
        </div>
      ))}
      <form action={formAction} ref={formRef}>
        <input type="text" name="message" placeholder="Hello!" />
        <button type="submit">Send</button>
      </form>
    </>
  );
}

export default function App() {
  const [messages, setMessages] = useState([
    { text: "Hello there!", sending: false, key: 1 }
  ]);
  async function sendMessage(formData) {
    const sentMessage = await deliverMessage(formData.get("message"));
    setMessages((messages) => [...messages, { text: sentMessage }]);
  }
  return <Thread messages={messages} sendMessage={sendMessage} />;
}
```

```javascript
export async function deliverMessage(message) {
  await new Promise((res) => setTimeout(res, 1000));
  return message;
}
```

--------------------------------

### Optimistically Adding Items to a List with useOptimistic Reducer

Source: https://github.com/reactjs/react.dev/blob/main/src/content/reference/react/useOptimistic.md

This example demonstrates how to use `useOptimistic` with a reducer to optimistically add items to a list, ensuring correct state updates even if the base list changes during a pending transition.

```javascript
import { useState, startTransition } from 'react';
import { addTodo } from './actions.js';
import TodoList from './TodoList';

export default function App() {
  const [todos, setTodos] = useState(
    { id: 1, text: 'Learn React' }
  ]);

  async function addTodoAction(newTodo) {
    const savedTodo = await addTodo(newTodo);
    startTransition(() => {
      setTodos(todos => [...todos, savedTodo]);
    });
  }

  return <TodoList todos={todos} addTodoAction={addTodoAction} />;
}
```

```javascript
import { useOptimistic, startTransition } from 'react';

export default function TodoList({ todos, addTodoAction }) {
  const [optimisticTodos, addOptimisticTodo] = useOptimistic(
    todos,
    (currentTodos, newTodo) => [
      ...currentTodos,
      { id: newTodo.id, text: newTodo.text, pending: true }
    ]
  );

  function handleAddTodo(text) {
    const newTodo = { id: crypto.randomUUID(), text: text };
    startTransition(async () => {
      addOptimisticTodo(newTodo);
      await addTodoAction(newTodo);
    });
  }

  return (
    <div>
      <button onClick={() => handleAddTodo('New todo')}>Add Todo</button>
      <ul>
        {optimisticTodos.map(todo => (
          <li key={todo.id}>
            {todo.text} {todo.pending && "(Adding...)"}
          </li>
        ))}
      </ul>
    </div>
  );
}
```

```javascript
export async function addTodo(todo) {
  await new Promise((res) => setTimeout(res, 1000));
  // In a real app, this would save to the server
  return { ...todo, pending: false };
}
```

--------------------------------

### Optimistic Delete Implementation with Error Recovery

Source: https://github.com/reactjs/react.dev/blob/main/src/content/reference/react/useOptimistic.md

Complete example showing optimistic deletion with error handling. The App component manages items and calls deleteItem, while ItemList uses useOptimistic to immediately update UI and rolls back on failure. Requires wrapping optimistic updates in startTransition.

```JavaScript
import { useState, startTransition } from 'react';
import { deleteItem } from './actions.js';
import ItemList from './ItemList';

export default function App() {
  const [items, setItems] = useState([
    { id: 1, name: 'Learn React' },
    { id: 2, name: 'Build an app' },
    { id: 3, name: 'Deploy to production' },
  ]);

  async function deleteAction(id) {
    await deleteItem(id);
    startTransition(() => {
      setItems(current => current.filter(item => item.id !== id));
    });
  }

  return <ItemList items={items} deleteAction={deleteAction} />;
}
```

```JavaScript
import { useState, useOptimistic, startTransition } from 'react';

export default function ItemList({ items, deleteAction }) {
  const [error, setError] = useState(null);
  const [optimisticItems, removeItem] = useOptimistic(
    items,
    (currentItems, idToRemove) =>
      currentItems.map(item =>
        item.id === idToRemove
          ? { ...item, deleting: true }
          : item
      )
  );

  function handleDelete(id) {
    setError(null);
    startTransition(async () => {
      removeItem(id);
      try {
        await deleteAction(id);
      } catch (e) {
        setError(e.message);
      }
    });
  }

  return (
    <div>
      <h2>Your Items</h2>
      <ul>
        {optimisticItems.map(item => (
          <li
            key={item.id}
            style={{
              opacity: item.deleting ? 0.5 : 1,
              textDecoration: item.deleting ? 'line-through' : 'none',
              transition: 'opacity 0.2s'
            }}
          >
            {item.name}
            <button
              onClick={() => handleDelete(item.id)}
              disabled={item.deleting}
              style={{ marginLeft: 8 }}
            >
              {item.deleting ? 'Deleting...' : 'Delete'}
            </button>
          </li>
        ))}
      </ul>
      {error && (
        <p style={{ color: 'red', padding: 8, background: '#fee' }}>
          {error}
        </p>
      )}
    </div>
  );
}
```

```JavaScript
export async function deleteItem(id) {
  await new Promise((res) => setTimeout(res, 1000));
  // Item 3 always fails to demonstrate error recovery
  if (id === 3) {
    throw new Error('Cannot delete. Permission denied.');
  }
}
```

### Actions

Source: https://github.com/reactjs/react.dev/blob/main/src/content/blog/2024/02/15/react-labs-what-we-have-been-working-on-february-2024.md

Alongside Actions, React introduces `useOptimistic` for managing optimistic state updates. This hook allows you to apply temporary UI updates that are automatically reverted once the final state commits. For Actions, `useOptimistic` enables optimistically setting the final data state on the client, assuming a successful submission, and then reverting to the server's actual data if needed. It works seamlessly with regular `async`/`await` operations.

--------------------------------

### New hook: useOptimistic

Source: https://github.com/reactjs/react.dev/blob/main/src/content/blog/2024/12/05/react-19.md

The `useOptimistic` hook is designed to handle optimistic updates by showing a final state while an asynchronous request is in progress. It immediately renders an optimistic value and automatically switches back to the original value once the update finishes or encounters an error. This pattern simplifies the UI logic needed to provide immediate feedback to users during data mutations.

