:root {
  color-scheme: light dark;
  font-family: system-ui, -apple-system, Segoe UI, Roboto, sans-serif;
}

body {
  margin: 0;
  background: #f6f7f9;
  color: #1f2933;
}

@media (prefers-color-scheme: dark) {
  body {
    background: #14161a;
    color: #e6e8eb;
  }
}

.app {
  max-width: 48rem;
  margin: 4rem auto;
  padding: 0 1rem;
}

.app h1 {
  margin: 0 0 1.5rem;
  font-size: 1.75rem;
}

.app-layout {
  display: grid;
  grid-template-columns: 14rem 1fr;
  gap: 1.5rem;
  align-items: start;
}

@media (max-width: 640px) {
  .app-layout {
    grid-template-columns: 1fr;
  }
}

.app-main {
  min-width: 0;
}

.empty-state {
  padding: 1rem 0;
}

.muted {
  color: #6b7280;
  font-style: italic;
}

.banner {
  padding: 0.75rem 1rem;
  border-radius: 0.5rem;
  margin-bottom: 1rem;
  font-size: 0.9rem;
}

.banner-error {
  background: #fee2e2;
  color: #991b1b;
}

@media (prefers-color-scheme: dark) {
  .banner-error {
    background: #3f1f1f;
    color: #fca5a5;
  }
}

/* Sidebar */

.sidebar {
  display: flex;
  flex-direction: column;
  gap: 0.75rem;
  padding: 0.75rem;
  background: white;
  border: 1px solid #e5e7eb;
  border-radius: 0.5rem;
}

@media (prefers-color-scheme: dark) {
  .sidebar {
    background: #1f2329;
    border-color: #2f343c;
  }
}

.sidebar-title {
  margin: 0;
  font-size: 0.75rem;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  color: #6b7280;
}

.sidebar-empty {
  margin: 0;
  font-size: 0.85rem;
}

.sidebar-rows {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  flex-direction: column;
  gap: 0.125rem;
}

.todo-list-row {
  width: 100%;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 0.5rem;
  padding: 0.5rem 0.6rem;
  background: transparent;
  border: none;
  border-left: 3px solid transparent;
  border-radius: 0.375rem;
  text-align: left;
  font-size: 0.95rem;
  color: inherit;
  cursor: pointer;
}

.todo-list-row:hover {
  background: #f3f4f6;
}

@media (prefers-color-scheme: dark) {
  .todo-list-row:hover {
    background: #262b32;
  }
}

.todo-list-row.active {
  background: #eff6ff;
  border-left-color: #2563eb;
  font-weight: 500;
}

@media (prefers-color-scheme: dark) {
  .todo-list-row.active {
    background: #1e2a3f;
  }
}

.todo-list-row-name {
  flex: 1;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.todo-list-row-count {
  font-size: 0.75rem;
  color: #6b7280;
  background: #e5e7eb;
  padding: 0.1rem 0.45rem;
  border-radius: 999px;
  flex-shrink: 0;
}

@media (prefers-color-scheme: dark) {
  .todo-list-row-count {
    background: #2f343c;
    color: #9ca3af;
  }
}

.todo-list-row.active .todo-list-row-count {
  background: #dbeafe;
  color: #1e40af;
}

@media (prefers-color-scheme: dark) {
  .todo-list-row.active .todo-list-row-count {
    background: #1e3a5f;
    color: #93c5fd;
  }
}

.add-list-form {
  display: flex;
  gap: 0.375rem;
  margin-top: 0.25rem;
}

.add-list-form input[type='text'] {
  flex: 1;
  min-width: 0;
  padding: 0.4rem 0.6rem;
  border: 1px solid #d1d5db;
  border-radius: 0.375rem;
  font-size: 0.9rem;
  background: white;
  color: inherit;
}

@media (prefers-color-scheme: dark) {
  .add-list-form input[type='text'] {
    background: #14161a;
    border-color: #2f343c;
  }
}

.add-list-form input[type='text']:focus {
  outline: 2px solid #2563eb;
  outline-offset: 1px;
}

.add-list-form button {
  padding: 0.4rem 0.7rem;
  background: #2563eb;
  color: white;
  border: none;
  border-radius: 0.375rem;
  font-size: 1rem;
  line-height: 1;
  cursor: pointer;
}

.add-list-form button:disabled {
  opacity: 0.5;
  cursor: not-allowed;
}

/* Main panel header */

.todo-list-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 0.5rem;
  margin-bottom: 1rem;
}

.todo-list-name {
  margin: 0;
  font-size: 1.25rem;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.todo-list-name-input {
  flex: 1;
  font-size: 1.25rem;
  font-weight: 600;
  padding: 0.25rem 0.5rem;
  border: 1px solid #2563eb;
  border-radius: 0.375rem;
  background: white;
  color: inherit;
}

@media (prefers-color-scheme: dark) {
  .todo-list-name-input {
    background: #1f2329;
  }
}

.todo-list-actions {
  display: flex;
  gap: 0.375rem;
  flex-shrink: 0;
}

.todo-list-actions button {
  padding: 0.35rem 0.7rem;
  background: transparent;
  border: 1px solid #d1d5db;
  border-radius: 0.375rem;
  font-size: 0.85rem;
  color: inherit;
  cursor: pointer;
}

.todo-list-actions button:hover {
  background: #f3f4f6;
}

@media (prefers-color-scheme: dark) {
  .todo-list-actions button {
    border-color: #2f343c;
  }
  .todo-list-actions button:hover {
    background: #262b32;
  }
}

.todo-list-actions .todo-list-delete:hover {
  background: #fee2e2;
  border-color: #fca5a5;
  color: #991b1b;
}

@media (prefers-color-scheme: dark) {
  .todo-list-actions .todo-list-delete:hover {
    background: #3f1f1f;
    border-color: #7f1d1d;
    color: #fca5a5;
  }
}

/* Add todo (item) form */

.add-todo-form {
  display: flex;
  gap: 0.5rem;
  margin-bottom: 1rem;
}

.add-todo-form input[type='text'] {
  flex: 1;
  padding: 0.6rem 0.75rem;
  border: 1px solid #d1d5db;
  border-radius: 0.5rem;
  font-size: 1rem;
  background: white;
  color: inherit;
}

@media (prefers-color-scheme: dark) {
  .add-todo-form input[type='text'] {
    background: #1f2329;
    border-color: #2f343c;
  }
}

.add-todo-form input[type='text']:focus {
  outline: 2px solid #2563eb;
  outline-offset: 1px;
}

.add-todo-form button {
  padding: 0.6rem 1.25rem;
  background: #2563eb;
  color: white;
  border: none;
  border-radius: 0.5rem;
  font-size: 1rem;
  cursor: pointer;
}

.add-todo-form button:disabled {
  opacity: 0.5;
  cursor: not-allowed;
}

/* Todo item rows */

.todo-rows {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  flex-direction: column;
  gap: 0.25rem;
}

.todo-row {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  padding: 0.6rem 0.75rem;
  border-radius: 0.5rem;
  background: white;
  border: 1px solid #e5e7eb;
}

@media (prefers-color-scheme: dark) {
  .todo-row {
    background: #1f2329;
    border-color: #2f343c;
  }
}

.todo-row-label {
  flex: 1;
  display: flex;
  align-items: center;
  gap: 0.6rem;
  cursor: pointer;
}

.todo-row.completed .todo-row-label span {
  text-decoration: line-through;
  color: #9ca3af;
}

.todo-row-delete {
  background: transparent;
  border: none;
  color: #9ca3af;
  font-size: 1.4rem;
  line-height: 1;
  cursor: pointer;
  padding: 0 0.25rem;
}

.todo-row-delete:hover {
  color: #ef4444;
}

